mapper.select:
select ask.id, ask.agent_id as agentId, ad.name as agentName, ask.definition_desc as definitionDesc, ask.exec_content as execContent, ask.return_data_format as returnDataFormat, coalesce(command_stat.command_count, 0) as commandCount, ask.update_time as updateTime, ask.status, ask.remark from agent_skill ask inner join agent_definition ad on ad.id = ask.agent_id left join ( select skill_id, count(1) as command_count from atomic_command where skill_id is not null group by skill_id ) command_stat on command_stat.skill_id = ask.id
and (ask.definition_desc like concat('%', #{pageRequest.keyword}, '%') or ask.exec_content like concat('%', #{pageRequest.keyword}, '%') or ask.return_data_format like concat('%', #{pageRequest.keyword}, '%') or ask.remark like concat('%', #{pageRequest.keyword}, '%') or ad.name like concat('%', #{pageRequest.keyword}, '%'))
and ask.agent_id = #{pageRequest.agentId}
and ad.name like concat('%', #{pageRequest.agentName}, '%')
and ask.status = #{pageRequest.status}
order by ask.update_time desc nulls last, ask.create_time desc nulls last limit #{size} offset #{offset}

select count(1) from agent_skill ask inner join agent_definition ad on ad.id = ask.agent_id
and (ask.definition_desc like concat('%', #{pageRequest.keyword}, '%') or ask.exec_content like concat('%', #{pageRequest.keyword}, '%') or ask.return_data_format like concat('%', #{pageRequest.keyword}, '%') or ask.remark like concat('%', #{pageRequest.keyword}, '%') or ad.name like concat('%', #{pageRequest.keyword}, '%'))
and ask.agent_id = #{pageRequest.agentId}
and ad.name like concat('%', #{pageRequest.agentName}, '%')
and ask.status = #{pageRequest.status}
